{"type": "email", "id": "email_004", "subject": "Employee Satisfaction Survey", "from": "michael.johnson@mediconnsolutions.com", "from_name": "Michael Johnson", "to": ["rachel.lee@mediconnsolutions.com"], "cc": ["emily.garcia@mediconnsolutions.com", "james.williams@mediconnsolutions.com", "patricia.brown@mediconnsolutions.com"], "date": "2022-03-01 16:30:00", "body": "Hi Rachel,

